completions.insertText:
healthcheck:
  test: ["CMD", "${1:curl}", "${2:-f}", "${3:http://localhost}"]
  interval: ${4:30s}
  timeout: ${5:10s}
  retries: ${6:3}
  start_period: ${7:10s}

deploy:
  replicas: ${1:1}
  resources:
    limits:
      cpus: '${2:0.5}'
      memory: ${3:512M}

${1:db}:
  image: ${2:postgres:16}
  environment:
    POSTGRES_DB: ${3:mydb}
    POSTGRES_USER: ${4:user}
    POSTGRES_PASSWORD: ${5:password}
  volumes:
    - ${6:db_data}:/var/lib/postgresql/data
  ports:
    - "${7:5432}:${8:5432}"
  restart: unless-stopped

${1:mysql}:
  image: mysql:${2:8}
  environment:
    MYSQL_ROOT_PASSWORD: ${3:rootpassword}
    MYSQL_DATABASE: ${4:mydb}
    MYSQL_USER: ${5:user}
    MYSQL_PASSWORD: ${6:password}
  volumes:
    - ${7:mysql_data}:/var/lib/mysql
  ports:
    - "${8:3306}:${9:3306}"
  restart: unless-stopped

${1:mongo}:
  image: mongo:${2:7}
  environment:
    MONGO_INITDB_ROOT_USERNAME: ${3:admin}
    MONGO_INITDB_ROOT_PASSWORD: ${4:password}
  volumes:
    - ${5:mongo_data}:/data/db
  ports:
    - "${6:27017}:${7:27017}"
  restart: unless-stopped

services:
  ${1:app}:
    build: ${2:.}
    ports:
      - "${3:3000}:${4:3000}"
    environment:
      - ${5:NODE_ENV}=${6:development}
    volumes:
      - ${7:.}:${8:/app}
    depends_on:
      - ${9:db}

  ${9:db}:
    image: ${10:postgres:16}
    environment:
      POSTGRES_PASSWORD: ${11:postgres}
    volumes:
      - ${12:db_data}:/var/lib/postgresql/data

volumes:
  ${12:db_data}:

healthcheck:
  test: ["CMD", "${1:curl}", "${2:-f}", "${3:http://localhost:8080/health}"]
  interval: ${4:30s}
  timeout: ${5:10s}
  retries: ${6:3}
  start_period: ${7:40s}
